import{_ as a,o as e,c as l,aw as i}from"./chunks/framework.DLufY-ao.js";const r="/workbook/assets/hash1.Ckds2ekl.png",m=JSON.parse('{"title":"Hash-table (Хэш-таблица)","description":"","frontmatter":{},"headers":[],"relativePath":"wiki/dev-commit/theory/data-structures/structures/hash.md","filePath":"wiki/dev-commit/theory/data-structures/structures/hash.md"}'),s={name:"wiki/dev-commit/theory/data-structures/structures/hash.md"};function h(d,t,o,n,c,u){return e(),l("div",null,[...t[0]||(t[0]=[i('<h1 id="hash-table-хэш-таблица" tabindex="-1">Hash-table (Хэш-таблица) <a class="header-anchor" href="#hash-table-хэш-таблица" aria-label="Permalink to &quot;Hash-table (Хэш-таблица)&quot;">​</a></h1><h2 id="информация" tabindex="-1">Информация <a class="header-anchor" href="#информация" aria-label="Permalink to &quot;Информация&quot;">​</a></h2><img src="'+r+'" width="350px"><blockquote><p>Принцип работы хэш-таблицы и хэш-функции</p></blockquote><div class="tip custom-block"><p class="custom-block-title">Хэш-таблица</p><ul><li><strong>Хэш-таблица</strong> - похожая на Map структура, , реализующая интерфейс ассоциативного массива и позволяющая хранить пары ключ/значение</li><li>Это похоже на массив, только вместо использются hash-коды, которые создаются самостоятельно или использовать уже готовые hash-функции</li><li>Она использует хэш-функцию для вычисления индекса в массиве из блоков данных, чтобы найти желаемое значение</li><li>Обычно хэш-функция принимает строку символов в качестве вводных данных и выводит числовое значение. Для одного и того же ввода хэш-функция должна возвращать одинаковое число. Если два разных ввода хэшируются с одним и тем же итогом, возникает коллизия. Цель в том, чтобы таких случаев было как можно меньше</li><li>Таким образом, когда вы вводите пару ключ/значение в хэш-таблицу, ключ проходит через хэш-функцию и превращается в число. В дальнейшем это число используется как фактический ключ, который соответствует определенному значению. Когда вы снова введёте тот же ключ, хэш-функция обработает его и вернет такой же числовой результат. Затем этот результат будет использован для поиска связанного значения</li><li><em>Назначение</em>: сокращение среднего времени поиска</li></ul></div><hr><h2 id="операции" tabindex="-1">Операции <a class="header-anchor" href="#операции" aria-label="Permalink to &quot;Операции&quot;">​</a></h2><ul><li>Добавление новой пары</li><li>Поиск</li><li>Удаление пары по ключу</li></ul><h2 id="сложность-алгоритма" tabindex="-1">Сложность алгоритма <a class="header-anchor" href="#сложность-алгоритма" aria-label="Permalink to &quot;Сложность алгоритма&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Алгоритм</th><th style="text-align:right;">Среднее значение</th><th style="text-align:right;">Худший случай</th></tr></thead><tbody><tr><td>Space</td><td style="text-align:right;">O(n)</td><td style="text-align:right;">O(n)</td></tr><tr><td>Search</td><td style="text-align:right;">O(1)</td><td style="text-align:right;">O(n)</td></tr><tr><td>Insert</td><td style="text-align:right;">O(1)</td><td style="text-align:right;">O(n)</td></tr><tr><td>Delete</td><td style="text-align:right;">O(1)</td><td style="text-align:right;">O(n)</td></tr></tbody></table>',10)])])}const b=a(s,[["render",h]]);export{m as __pageData,b as default};
